userDefinedLinkHintCss:
div > .vimiumHintMarker {
/* linkhint boxes */
background: -webkit-gradient(linear, left top, left bottom, color-stop(0%,#FFF785),
  color-stop(100%,#FFC542));
border: 1px solid #E3BE23;
}

div > .vimiumHintMarker span {
/* linkhint text */
color: black;
font-weight: bold;
font-size: 12px;
}

div > .vimiumHintMarker > .matchingCharacter {
}

#vomnibar {
  top: 20px;
  width: calc(100% - 40px);
  left: 20px;
  border: 2px solid #babbf1;
  border-radius: 0px;
  background-color: #303446;
  color: #c6d0f5;
}

#vomnibar-search-area {
  background-color: unset;
  display: flex;
}

#vomnibar-search-area::before {
  content: "Navigate:";
  display: flex;
  height: 20px;
  font-size: 18px;
  margin-right: 5px;
  line-height: 16px;
  white-space: nowrap;
  color: #e5c890;
}

#vomnibar input {
  background-color: unset;
  padding: 0px;
  color: #c6d0f5;
  box-shadow: unset;
  display: inline-block;
  height: 20px;
}

#vomnibar ul {
  border-top: 2px solid #babbf1;
}

#vomnibar li {
  border-bottom: 2px solid #737994;
}

#vomnibar li.selected {
  background-color: #232634;
}

#vomnibar li .top-half .source.no-insert-text {
  display: none;
}

#vomnibar li .top-half .source {
  margin: 0px;
}

#vomnibar li .bottom-half .source.no-insert-text {
  visibility: visible;
}
